INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (503, 'Introducing GPT-5', 'We are introducing GPT‑5, our best AI system yet. GPT‑5 is a significant leap in intelligence over all our previous models, featuring state-of-the-art performance across coding, math, writing, health, visual perception, and more.', 'We are introducing GPT‑5, our best AI system yet. GPT‑5 is a significant leap in intelligence over all our previous models, featuring state-of-the-art performance across coding, math, writing, health, visual perception, and more.', 14, 'OpenAI Blog', 'https://openai.com/index/introducing-gpt-5', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Release"]', '2025-08-07 00:00:00.000000', '2026-04-07 06:56:48.306661', 'https://openai.com/index/introducing-gpt-5', 0.0, 0);
