INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (539, 'AI in Australia—OpenAI’s Economic Blueprint', 'Today, OpenAI, in partnership with Mandala Partners, is sharing the OpenAI AI Economic Blueprint for Australia. At a time when boosting productivity has emerged as a national priority for Australia, the Blueprint provides a clear, actionable plan for how Australia can unlock the full economic and social potential of artificial intelligence.', 'Today, OpenAI, in partnership with Mandala Partners, is sharing the OpenAI AI Economic Blueprint for Australia. At a time when boosting productivity has emerged as a national priority for Australia, the Blueprint provides a clear, actionable plan for how Australia can unlock the full economic and social potential of artificial intelligence.', 14, 'OpenAI Blog', 'https://openai.com/global-affairs/openais-australia-economic-blueprint', '', 'ai_tech', '["OpenAI", "Company", "AI", "GPT"]', '2025-06-30 07:00:00.000000', '2026-04-07 06:56:48.307024', 'https://openai.com/global-affairs/openais-australia-economic-blueprint', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (540, 'Customizable, no-code voice agent automation with GPT-4o', 'Retell AI is transforming the call center with AI voice automation powered by GPT-4o and GPT-4.1. Its no-code platform enables businesses to launch natural, real-time voice agents that cut call costs, boost CSAT, and automate customer conversations—without scripts or hold times.', 'Retell AI is transforming the call center with AI voice automation powered by GPT-4o and GPT-4.1. Its no-code platform enables businesses to launch natural, real-time voice agents that cut call costs, boost CSAT, and automate customer conversations—without scripts or hold times.', 14, 'OpenAI Blog', 'https://openai.com/index/retell-ai', '', 'ai_tech', '["OpenAI", "B2B Story", "AI", "GPT"]', '2025-06-26 10:00:00.000000', '2026-04-07 06:56:48.307034', 'https://openai.com/index/retell-ai', 0.0, 0);
INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (541, 'Driving scalable growth with OpenAI o3, GPT-4.1, and CUA', 'Unify, an AI-powered GTM platform, uses OpenAI’s o3, GPT-4.1, and CUA to automate prospecting, research, and outreach. With hyper-personalized messaging and an always-on workflow, Unify helps teams generate pipeline at scale while focusing on high-impact customer interactions.', 'Unify, an AI-powered GTM platform, uses OpenAI’s o3, GPT-4.1, and CUA to automate prospecting, research, and outreach. With hyper-personalized messaging and an always-on workflow, Unify helps teams generate pipeline at scale while focusing on high-impact customer interactions.', 14, 'OpenAI Blog', 'https://openai.com/index/unify', '', 'ai_tech', '["OpenAI", "GPT", "AI", "API"]', '2025-06-24 00:00:00.000000', '2026-04-07 06:56:48.307045', 'https://openai.com/index/unify', 0.0, 0);
