INSERT OR REPLACE INTO rss_articles (id, title, summary, content, source_id, source_name, source_url, author, category, tags, publish_time, fetch_time, guid, quality_score, view_count) VALUES (591, 'Introducing 4o Image Generation', 'At OpenAI, we have long believed image generation should be a primary capability of our language models. That’s why we’ve built our most advanced image generator yet into GPT‑4o. The result—image generation that is not only beautiful, but useful.', 'At OpenAI, we have long believed image generation should be a primary capability of our language models. That’s why we’ve built our most advanced image generator yet into GPT‑4o. The result—image generation that is not only beautiful, but useful.', 14, 'OpenAI Blog', 'https://openai.com/index/introducing-4o-image-generation', '', 'ai_tech', '["OpenAI", "GPT", "AI", "Product"]', '2025-03-25 11:05:00.000000', '2026-04-07 06:56:48.307531', 'https://openai.com/index/introducing-4o-image-generation', 0.0, 0);
